<script setup lang="ts">defineProps<{modelValue?:string;options:{label:string;value:string}[];label?:string;tone?:'life'|'study'}>();defineEmits<{"update:modelValue":[string]}>()</script><template><label class="xj-field"><span v-if="label" class="xj-label">{{label}}</span><span class="xj-input-wrap" :class="tone||'life'"><select class="xj-input" :value="modelValue" @change="$emit('update:modelValue',($event.target as HTMLSelectElement).value)"><option v-for="o in options" :key="o.value" :value="o.value">{{o.label}}</option></select><span>⌄</span></span></label></template>
